using TMPro; using UnityEngine; using NabyeolDabyeolDreamPuzzle.Story; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.UI { public class StoryTextUI:MonoBehaviour{ [SerializeField] StoryManager storyManager; [SerializeField] GoalManager goalManager; [SerializeField] GameObject storyPanel; [SerializeField] TMP_Text speakerText,dialogueText; [SerializeField] bool showStageStartOnStart=true; [SerializeField] bool hidePanelWhenEmpty=true; void Awake(){ storyManager??=FindAnyObjectByType<StoryManager>(); goalManager??=FindAnyObjectByType<GoalManager>(); } void OnEnable(){ if(goalManager!=null){ goalManager.OnStageCleared+=ShowCurrentStageClearLine; goalManager.OnStageFailed+=ShowCurrentStageFailLine; }} void OnDisable(){ if(goalManager!=null){ goalManager.OnStageCleared-=ShowCurrentStageClearLine; goalManager.OnStageFailed-=ShowCurrentStageFailLine; }} void Start(){ if(showStageStartOnStart) ShowCurrentStageStartLine();} public void ShowCurrentStageStartLine()=>ShowLine(storyManager?storyManager.GetCurrentStageStartLine():null); public void ShowCurrentStageClearLine()=>ShowLine(storyManager?storyManager.GetCurrentStageClearLine():null); public void ShowCurrentStageFailLine()=>ShowLine(storyManager?storyManager.GetCurrentStageFailLine():null); public void ShowLine(StoryLineData line){ if(line==null||!line.IsValid()){Clear(); return;} ShowText(line.SpeakerName,line.Text);} public void ShowText(string speaker,string text){ Show(); if(speakerText)speakerText.text=speaker??""; if(dialogueText)dialogueText.text=text??"";} public void Clear(){ if(speakerText)speakerText.text=""; if(dialogueText)dialogueText.text=""; if(hidePanelWhenEmpty)Hide();} public void Show(){ if(storyPanel)storyPanel.SetActive(true);} public void Hide(){ if(storyPanel)storyPanel.SetActive(false);} } }
